const API = "http://127.0.0.1:8000";

/* =========================
   CORE REQUEST HELPER
========================= */
const request = async (url, options = {}) => {
  const res = await fetch(`${API}${url}`, {
    headers: {
      "Content-Type": "application/json",
      ...options.headers,
    },
    ...options,
  });

  let data;

  // safely handle JSON or text responses
  try {
    data = await res.json();
  } catch (e) {
    data = await res.text();
  }

  if (!res.ok) {
    throw new Error(data?.detail || data || "Request failed");
  }

  return data;
};

/* =========================
   AUTH
========================= */
export const registerUser = (data) => {
  return request("/api/auth/register", {
    method: "POST",
    body: JSON.stringify(data),
  });
};

export const loginUser = async (data) => {
  const res = await request("/api/auth/login", {
    method: "POST",
    body: JSON.stringify(data),
  });

  // 🔥 store role + user info automatically
  if (res) {
    if (res.userId) localStorage.setItem("userId", res.userId);
    if (res.role) localStorage.setItem("role", res.role);
    if (res.name) localStorage.setItem("name", res.name);
    if (res.token) localStorage.setItem("token", res.token);
  }

  return res;
};

/* =========================
   PATIENTS
========================= */
export const getPatients = () => {
  return request("/api/patients");
};

export const addPatient = (data) => {
  return request("/api/patients", {
    method: "POST",
    body: JSON.stringify(data),
  });
};

/* =========================
   APPOINTMENTS
========================= */
export const getAppointments = () => {
  return request("/api/appointments");
};

export const addAppointment = (data) => {
  return request("/api/appointments", {
    method: "POST",
    body: JSON.stringify(data),
  });
};

/* =========================
   PRESCRIPTIONS
========================= */
export const getPrescriptions = () => {
  return request("/api/prescriptions");
};

export const addPrescription = (data) => {
  return request("/api/prescriptions", {
    method: "POST",
    body: JSON.stringify(data),
  });
};

/* =========================
   OPTIONAL SEARCH HELPERS
========================= */

// If backend supports search
export const searchPatientByPhone = (phone) => {
  return request(`/api/patients/search?phone=${phone}`);
};
